To declare an `unordered_map` in C++ with `std::string` keys mapping to `std::vector` values, you can use the following syntax:

```cpp
#include <unordered_map>
#include <vector>
#include <string>

int main() {
    std::unordered_map<std::string, std::vector<int>> myMap;

    // Inserting values into the unordered_map
    myMap["key1"].push_back(10);
    myMap["key1"].push_back(20);
    myMap["key2"].push_back(30);
    myMap["key2"].push_back(40);

    // Accessing and printing values from the unordered_map
    for (const auto& pair : myMap) {
        std::cout << "Key: " << pair.first << ", Values: ";
        for (int value : pair.second) {
            std::cout << value << " ";
        }
        std::cout << std::endl;
    }

    return 0;
}
```

